import{_ as a,o as t,c as p,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"普适化射击技巧","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/射击类/普适化射击技巧.md","filePath":"4.资源分区/6.技艺及称号/射击类/普适化射击技巧.md"}'),b={name:"4.资源分区/6.技艺及称号/射击类/普适化射击技巧.md"};function o(d,e,_,l,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"普适化射击技巧",tabindex:"-1"},[n("普适化射击技巧 "),r("a",{class:"header-anchor",href:"#普适化射击技巧","aria-label":'Permalink to "普适化射击技巧"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),s('<h1 id="普适化射击技巧-1" tabindex="-1">普适化射击技巧 <a class="header-anchor" href="#普适化射击技巧-1" aria-label="Permalink to &quot;普适化射击技巧&quot;">​</a></h1><p>火力压制<br> D+500<br> 描述:<br> 火力压制是通过集中火力对敌方进行持续攻击的军事行动，旨在削弱敌方战斗力并限制其行动自由<br> 效果:<br> 你以标准动作执行【火力压制】，指定一个目标对其进行一次枪械或弓弩攻击，使用的武器需要具有【长点射】或是【连射】特性，目标需以反射对你此次的伤害出目进行豁免，若豁免失败则进入【被火力压制】，持续一轮</p><p>【被火力压制】:受到此效果的目标陷入创伤来源的D级困难地形并在攻击上受到3点环境减值，移动速度降低15点，最低降低到1。</p><p>火力倾泻<br> D+1000<br> 使用限制:具有【连射】<br> 描述:<br> 该操作又被叫做“泼水”，这种射击方式通常需要结合多种控枪技巧，例如“点、拉、扫、甩”等动作，以控制枪口上跳和散布，从而提高射击精度和杀伤效果<br> 效果:<br> 你以整轮动作执行【火力倾泻】，进入【火力倾斜】状态，并进行一次枪械或弓弩攻击，【火力倾斜】持续一轮，执行此技艺必须使用具有【连射】的武器</p><p>【火力倾斜】:具有此效果的单位，其攻击作用将转化为等同于射程范围半径的180°扇形范围的对所有单位生效的攻击，并使被攻击目标需使用反射豁免出目，本次攻击上也将获得3点士气加值。</p><p>狙击<br> D+500<br> 使用限制:1场景1次且需处于被所有敌对单位无法定位状态<br> 描述:<br> 狙击是枪械射击中一种以隐蔽潜伏方式，对暴露或特定目标进行远距离精准打击的军事战术，其核心在于通过高精度射击和隐蔽行动，实现对关键目标的快速清除。<br> 效果:<br> 你以整轮动作进行一次施展【狙击】的攻击。</p><p>【狙击】:持有此状态的目标在攻击命中时目标需进行强韧豁免承受差值伤害，并且攻击上附带C级措手不及与【9加骰】在进行攻击检定时获得5DP的增强加值</p><p>射击节奏<br> C+1000<br> 描述:<br> 掌握射击的节奏，点射，连射还是全自动？合适的节奏也许可以让你手感火热，帮助你更有效的杀伤敌人，但当然不会让你的杀敌变的优雅，毕竟杀戮本身就是暴力的<br> 效果:<br> 你在攻击上获得【激昂】效果，但该【激昂】仅在你使用可以被枪械与弓弩类武器施展的技艺时生效，以及在战斗内时每经历一轮且你使用过枪械或弓弩攻击，那么你获得1层【致命节奏】，至多可以获得等同于敏捷属性层，并且在进行枪械或弓弩攻击时获得2点增强加值，你进行的攻击视为始终提升至长点射。</p><p>【致命节奏】:持有该状态的单位在攻击上获得等同于层数点技艺加值</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const m=a(b,[["render",o]]);export{f as __pageData,m as default};
